import React from "react";
import { Routes, Route, Navigate } from "react-router-dom";

// Public Pages
import LandingPage from "./pages/Landing/LandingPage";
import Login from "./pages/Auth/Login";
import Register from "./pages/Auth/Register";

// Layout
import DashboardLayout from "./components/DashboardLayout";

// Admin
import AdminDashboard from "./pages/Admin/AdminDashboard";

// Freelancer
import FreelancerDashboard from "./pages/Freelancer/FreelancerDashboard";
import FindProjects from "./pages/Freelancer/FindProjects";
import MyProjects from "./pages/Client/MyProjects";
import MyProposals from "./pages/Freelancer/MyProposals";
import Profile from "./pages/Freelancer/Profile";

// Client
import ClientDashboard from "./pages/Client/ClientDashboard";
import PostProject from "./pages/Client/PostProject";
import Freelancers from "./pages/Client/Freelancers";

// Protected
import ProtectedRoute from "./components/ProtectedRoute";

function App() {
  return (
    <Routes>

      {/* ================= PUBLIC ================= */}
      <Route path="/" element={<LandingPage />} />
      <Route path="/login" element={<Login />} />
      <Route path="/register" element={<Register />} />

      {/* ================= PROTECTED LAYOUT ================= */}
      <Route element={<DashboardLayout />}>

        {/* ADMIN */}
        <Route
          path="/admin/dashboard"
          element={
            <ProtectedRoute role="admin">
              <AdminDashboard />
            </ProtectedRoute>
          }
        />

        {/* FREELANCER */}
        <Route
          path="/freelancer/dashboard"
          element={
            <ProtectedRoute role="freelancer">
              <FreelancerDashboard />
            </ProtectedRoute>
          }
        />

        <Route
          path="/freelancer/find-projects"
          element={
            <ProtectedRoute role="freelancer">
              <FindProjects />
            </ProtectedRoute>
          }
        />

        <Route
          path="/freelancer/my-projects"
          element={
            <ProtectedRoute role="freelancer">
              <MyProjects />
            </ProtectedRoute>
          }
        />

        <Route
          path="/freelancer/proposals"
          element={
            <ProtectedRoute role="freelancer">
              <MyProposals />
            </ProtectedRoute>
          }
        />

        <Route
          path="/freelancer/profile"
          element={
            <ProtectedRoute role="freelancer">
              <Profile />
            </ProtectedRoute>
          }
        />

        {/* CLIENT */}
        <Route
          path="/client/dashboard"
          element={
            <ProtectedRoute role="client">
              <ClientDashboard />
            </ProtectedRoute>
          }
        />

        <Route
          path="/client/post-project"
          element={
            <ProtectedRoute role="client">
              <PostProject />
            </ProtectedRoute>
          }
        />

        <Route
          path="/client/my-projects"
          element={
            <ProtectedRoute role="client">
              <MyProjects />
            </ProtectedRoute>
          }
        />

        <Route
          path="/client/freelancers"
          element={
            <ProtectedRoute role="client">
              <Freelancers />
            </ProtectedRoute>
          }
        />

      </Route>

      {/* DEFAULT */}
      <Route path="*" element={<Navigate to="/" />} />

    </Routes>
  );
}

export default App;
